INSERT INTO `v1_a6d7f06e43f9ed9bc445d32c3eccff482e38c59efec2bb17fb4e725a301cb3a9` VALUES ("フリーマーケットを訪れたジータが出会ったのは\n城をこっそり抜け出していたペコリーヌだった。", "フリーマーケット会場", "青空の下で謁見", 5118061, 10118, 2834, 8, 7, 20063115, 40, 2, "ペコリーヌとの出会い", 1, 0, 91002);
INSERT INTO `v1_a6d7f06e43f9ed9bc445d32c3eccff482e38c59efec2bb17fb4e725a301cb3a9` VALUES ("ジータたちがフリーマーケットを巡っていると\n露店を出していたマホに声をかけられる。", "フリーマーケット会場", "未来の騎空団\nマスコット？", 5118062, 10118, 2835, 8, 7, 20063115, 40, 2, "マホとの出会い", 1, 0, 91002);
INSERT INTO `v1_a6d7f06e43f9ed9bc445d32c3eccff482e38c59efec2bb17fb4e725a301cb3a9` VALUES ("ジータが騎空団への依頼を確認していると、\n高笑いをしながらアキノが現れる。", "ランドソル市街地", "お嬢さまからの\n緊急依頼", 5118063, 10118, 2837, 8, 7, 20063115, 40, 2, "アキノとの出会い", 1, 0, 91002);
INSERT INTO `v1_a6d7f06e43f9ed9bc445d32c3eccff482e38c59efec2bb17fb4e725a301cb3a9` VALUES ("ジータたちは、フリーマーケット会場で\n少し困った様子のジュンを見かける。", "フリーマーケット会場", "黄金色の悩みごと", 5118064, 10118, 4108402, 8, 18, 20063115, 40, 2, "ジュンとの出会い", 1, 0, 91002);
INSERT INTO `v1_a6d7f06e43f9ed9bc445d32c3eccff482e38c59efec2bb17fb4e725a301cb3a9` VALUES ("フリーマーケットの隅で開かれる格闘大会──\nそこにはカオリもいて……？", "フリーマーケット会場", "白熱！　格闘大会！", 5118065, 10118, 4107402, 8, 18, 20063115, 40, 2, "カオリとの出会い", 1, 0, 91002);
INSERT INTO `v1_a6d7f06e43f9ed9bc445d32c3eccff482e38c59efec2bb17fb4e725a301cb3a9` VALUES ("太鼓祭を控えるオーエド町──\nジータは、困った様子のニノンと出会う。", "オーエド町", "祭り太鼓はオーエドの華", 5118066, 10118, 9000227, 8, 16, 20063115, 40, 2, "ニノンとの出会い", 1, 1, 91002);
INSERT INTO `v1_a6d7f06e43f9ed9bc445d32c3eccff482e38c59efec2bb17fb4e725a301cb3a9` VALUES ("ビカラはイベントに出演中のスズナを見かける。\nしかし、スズナはどこか困っているようで……？", "フリーマーケット会場", "人気者は遅れて\nやってくる", 5118067, 10118, 2101181, 8, 19, 20063115, 40, 3, "スズナとの出会い", 1, 0, 91002);
INSERT INTO `v1_a6d7f06e43f9ed9bc445d32c3eccff482e38c59efec2bb17fb4e725a301cb3a9` VALUES ("ビカラたちが街を散策していると、通りかかった\nナナカが興奮した様子で近づいてきて……？", "ランドソル市街地", "巫女・ミーツ・魔法少女", 5118068, 10118, 4109402, 8, 18, 20063115, 40, 3, "ナナカとの出会い", 1, 0, 91002);
INSERT INTO `v1_a6d7f06e43f9ed9bc445d32c3eccff482e38c59efec2bb17fb4e725a301cb3a9` VALUES ("ネズ耳をなくしてしまい絶望するビカラ。同じ頃\nキャルとコッコロは落とし物を拾っており……", "フリーマーケット会場", "ネズ耳は二度なくなる", 5118069, 10118, 4305402, 8, 18, 20063115, 40, 3, "キャル＆コッコロとの出会い", 1, 0, 91002);
INSERT INTO `v1_a6d7f06e43f9ed9bc445d32c3eccff482e38c59efec2bb17fb4e725a301cb3a9` VALUES ("街外れでひと休みをしていたビカラたちは、\nすっかりゴキゲンな様子のユカリと出会う。", "ランドソル市街地", "この出会いにカンパイ！", 5118070, 10118, 4101402, 8, 18, 20063115, 40, 3, "ユカリとの出会い", 1, 0, 91002);
INSERT INTO `v1_a6d7f06e43f9ed9bc445d32c3eccff482e38c59efec2bb17fb4e725a301cb3a9` VALUES ("ビカラは、人混みに怯えるアオイを心配し、\n陽気に声をかけるも……", "ランドソル市街地", "陰陽アンサンブル", 5118071, 10118, 4106402, 8, 18, 20063115, 40, 3, "アオイとの出会い", 1, 0, 91002);
INSERT INTO `v1_a6d7f06e43f9ed9bc445d32c3eccff482e38c59efec2bb17fb4e725a301cb3a9` VALUES ("ビカラがフリーマーケット会場を歩いていると\n占いをしていたシノブに声をかけられる。", "フリーマーケット会場", "運試し十番勝負！", 5118072, 10118, 2836, 8, 7, 20063115, 40, 3, "シノブとの出会い", 1, 1, 91002);
INSERT INTO `v1_a6d7f06e43f9ed9bc445d32c3eccff482e38c59efec2bb17fb4e725a301cb3a9` VALUES (0, 0, "彼女たちの新たな日常", 5118600, 10118, 0, 0, 0, 20063115, 0, 1, "オープニング", 0, 0, 0);
